const fs = require('fs');
const path = require('path');
const crypto = require('crypto');
const { execSync } = require('child_process');

class PackageLockManager {
  constructor(projectRoot = process.cwd()) {
    this.projectRoot = path.resolve(projectRoot);
    this.packageJsonPath = path.join(this.projectRoot, 'package.json');
    this.packageLockPath = path.join(this.projectRoot, 'package-lock.json');
    this.allowedCommands = ['install', 'update', 'audit', 'ci'];
  }

  validatePath(filePath) {
    const resolvedPath = path.resolve(filePath);
    if (!resolvedPath.startsWith(this.projectRoot)) {
      throw new Error('Path traversal detected - access denied');
    }
    return resolvedPath;
  }

  validateCommand(command) {
    if (!this.allowedCommands.includes(command)) {
      throw new Error(`Command not allowed: ${command}`);
    }
    return command;
  }

  fileExists(filePath) {
    try {
      const validPath = this.validatePath(filePath);
      return fs.existsSync(validPath);
    } catch (error) {
      console.error(`Error checking file existence: ${error.message}`);
      return false;
    }
  }

  readJsonFile(filePath) {
    try {
      const validPath = this.validatePath(filePath);
      const content = fs.readFileSync(validPath, 'utf8');
      return JSON.parse(content);
    } catch (error) {
      throw new Error(`Failed to read JSON file: ${error.message}`);
    }
  }

  writeJsonFile(filePath, data) {
    try {
      const validPath = this.validatePath(filePath);
      const content = JSON.stringify(data, null, 2) + '\n';
      fs.writeFileSync(validPath, content, { mode: 0o644 });
      return true;
    } catch (error) {
      throw new Error(`Failed to write JSON file: ${error.message}`);
    }
  }

  calculateFileHash(filePath) {
    try {
      const validPath = this.validatePath(filePath);
      const content = fs.readFileSync(validPath);
      return crypto.createHash('sha256').update(content).digest('hex');
    } catch (error) {
      throw new Error(`Failed to calculate hash: ${error.message}`);
    }
  }

  generatePackageLock() {
    if (!this.fileExists(this.packageJsonPath)) {
      throw new Error('package.json not found in project root');
    }

    console.log('Generating package-lock.json...');
    
    try {
      execSync('npm install --package-lock-only', {
        cwd: this.projectRoot,
        stdio: 'inherit',
        env: { ...process.env, NODE_ENV: 'production' }
      });
      
      console.log('package-lock.json generated successfully');
      return true;
    } catch (error) {
      throw new Error(`Failed to generate package-lock.json: ${error.message}`);
    }
  }

  validatePackageLock() {
    if (!this.fileExists(this.packageLockPath)) {
      throw new Error('package-lock.json not found');
    }

    try {
      const lockData = this.readJsonFile(this.packageLockPath);
      
      if (!lockData.lockfileVersion) {
        throw new Error('Invalid package-lock.json: missing lockfileVersion');
      }

      if (!lockData.packages) {
        throw new Error('Invalid package-lock.json: missing packages');
      }

      console.log('package-lock.json validation passed');
      return true;
    } catch (error) {
      throw new Error(`Validation failed: ${error.message}`);
    }
  }

  verifyIntegrity() {
    console.log('Verifying package integrity...');
    
    try {
      execSync('npm audit signatures', {
        cwd: this.projectRoot,
        stdio: 'inherit'
      });
      
      console.log('Integrity verification completed');
      return true;
    } catch (error) {
      console.warn('Integrity verification encountered issues');
      return false;
    }
  }

  cleanInstall() {
    if (!this.fileExists(this.packageLockPath)) {
      throw new Error('package-lock.json required for clean install');
    }

    console.log('Performing clean install (npm ci)...');
    
    try {
      execSync('npm ci', {
        cwd: this.projectRoot,
        stdio: 'inherit',
        env: { ...process.env, NODE_ENV: 'production' }
      });
      
      console.log('Clean install completed successfully');
      return true;
    } catch (error) {
      throw new Error(`Clean install failed: ${error.message}`);
    }
  }

  updateDependencies(packageNames = []) {
    const sanitizedPackages = packageNames.filter(pkg => {
      return typeof pkg === 'string' && /^[@a-z0-9-_\/]+$/i.test(pkg);
    });

    if (packageNames.length !== sanitizedPackages.length) {
      throw new Error('Invalid package names detected');
    }

    const updateCmd = sanitizedPackages.length > 0
      ? `npm update ${sanitizedPackages.join(' ')}`
      : 'npm update';

    console.log(`Updating dependencies: ${updateCmd}`);
    
    try {
      execSync(updateCmd, {
        cwd: this.projectRoot,
        stdio: 'inherit'
      });
      
      console.log('Dependencies updated successfully');
      return true;
    } catch (error) {
      throw new Error(`Update failed: ${error.message}`);
    }
  }

  auditDependencies(fix = false) {
    const auditCmd = fix ? 'npm audit fix' : 'npm audit';
    
    console.log(`Running security audit: ${auditCmd}`);
    
    try {
      execSync(auditCmd, {
        cwd: this.projectRoot,
        stdio: 'inherit'
      });
      
      console.log('Security audit completed');
      return true;
    } catch (error) {
      console.error('Security vulnerabilities detected');
      return false;
    }
  }

  comparePackageLocks(lockPath1, lockPath2) {
    try {
      const lock1 = this.readJsonFile(lockPath1);
      const lock2 = this.readJsonFile(lockPath2);

      const hash1 = crypto.createHash('sha256').update(JSON.stringify(lock1.packages)).digest('hex');
      const hash2 = crypto.createHash('sha256').update(JSON.stringify(lock2.packages)).digest('hex');

      return {
        identical: hash1 === hash2,
        hash1,
        hash2
      };
    } catch (error) {
      throw new Error(`Comparison failed: ${error.message}`);
    }
  }

  backupPackageLock() {
    if (!this.fileExists(this.packageLockPath)) {
      throw new Error('No package-lock.json to backup');
    }

    const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
    const backupPath = path.join(this.projectRoot, `package-lock.json.backup-${timestamp}`);
    
    try {
      const validBackupPath = this.validatePath(backupPath);
      fs.copyFileSync(this.packageLockPath, validBackupPath);
      console.log(`Backup created: ${path.basename(backupPath)}`);
      return backupPath;
    } catch (error) {
      throw new Error(`Backup failed: ${error.message}`);
    }
  }

  generateReport() {
    const report = {
      timestamp: new Date().toISOString(),
      projectRoot: this.projectRoot,
      files: {}
    };

    if (this.fileExists(this.packageJsonPath)) {
      const packageJson = this.readJsonFile(this.packageJsonPath);
      report.files.packageJson = {
        exists: true,
        hash: this.calculateFileHash(this.packageJsonPath),
        name: packageJson.name,
        version: packageJson.version,
        dependencies: Object.keys(packageJson.dependencies || {}).length,
        devDependencies: Object.keys(packageJson.devDependencies || {}).length
      };
    }

    if (this.fileExists(this.packageLockPath)) {
      const packageLock = this.readJsonFile(this.packageLockPath);
      report.files.packageLock = {
        exists: true,
        hash: this.calculateFileHash(this.packageLockPath),
        lockfileVersion: packageLock.lockfileVersion,
        packages: Object.keys(packageLock.packages || {}).length
      };
    }

    return report;
  }
}

